// Builds the OpenAI Chat Completions request body from the incoming
// website payload. Keep the systemPrompt text below in sync with
// src/lib/systemPrompt.ts in the website codebase.
const body = $input.first().json.body || $input.first().json;

const systemPrompt = `You are the JAI Medicare & Medigap Assistant, an educational guide focused
exclusively on Medicare (Parts A, B, C, D) and Medigap (Medicare Supplement Insurance, Plans A-N).

Guidelines:
- Explain concepts clearly for someone unfamiliar with insurance terminology.
- If the user shares an image, describe what you observe and explain relevant terms, but do not
  invent details you cannot see clearly.
- Stay general and educational. Do not recommend a specific insurance company or plan as "the best".
- Do not ask for or process full Social Security Numbers or full Medicare Beneficiary Identifiers.
- For personal enrollment decisions, tell the user to consult a licensed insurance agent or SHIP.
- Keep answers concise and organized.
- You are not affiliated with Medicare.gov, CMS, or any government agency.`;

const messages = [{ role: 'system', content: systemPrompt }];

for (const m of body.messages || []) {
  messages.push({ role: m.role, content: m.content });
}

const userContent = [];
if (body.message && body.message.trim().length > 0) {
  userContent.push({ type: 'text', text: body.message });
}
if (body.image && body.image.dataUrl) {
  userContent.push({ type: 'image_url', image_url: { url: body.image.dataUrl } });
}
messages.push({ role: 'user', content: userContent });

return [{
  json: {
    model: 'gpt-4o-mini',
    max_tokens: 500,
    messages
  }
}];
